import React, { useState, useEffect } from "react";

const API = "https://prasa-backend-1.onrender.com";

export default function AddTravel({ employee }) {
  const [form, setForm] = useState({
    travel_date: "",
    location_from: "",
    location_to: "",
    purpose: "",
    mode_of_travel: "",
    amount: "",
  });

  const [travelList, setTravelList] = useState([]);
  const [filterMonth, setFilterMonth] = useState("");

  // FIX: Ensure returned data is always an array
  const loadTravel = async () => {
    try {
      const res = await fetch(`${API}/travel/${employee.empld}`);
      const json = await res.json();

      const list = Array.isArray(json.data) ? json.data : [];
      setTravelList(list);
    } catch (err) {
      console.error("Travel Load Error:", err);
    }
  };

  useEffect(() => {
    if (employee?.empld) loadTravel();
  }, [employee]);

  const saveTravel = async () => {
    if (
      !form.travel_date ||
      !form.location_from ||
      !form.location_to ||
      !form.amount
    ) {
      alert("Please fill all required fields!");
      return;
    }

    try {
      const res = await fetch(`${API}/travel/add`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, empld: employee.empld }),
      });

      const json = await res.json();
      if (json.success) {
        alert("Travel expense added!");
        setForm({
          travel_date: "",
          location_from: "",
          location_to: "",
          purpose: "",
          mode_of_travel: "",
          amount: "",
        });
        loadTravel();
      } else {
        alert(json.message);
      }
    } catch (err) {
      console.error("Save error:", err);
    }
  };

  const deleteTravel = async (id) => {
    if (!window.confirm("Delete this entry?")) return;

    await fetch(`${API}/travel/delete/${id}`, { method: "DELETE" });
    loadTravel();
  };

  // Month filtering
  const filteredList = travelList.filter((t) =>
    filterMonth ? t.travel_date.startsWith(filterMonth) : true
  );

  return (
    <div className="page-container">
      <h2>Travel Expense</h2>

      {/* Travel Form */}
      <div className="form-card">
        <input
          type="date"
          value={form.travel_date}
          onChange={(e) => setForm({ ...form, travel_date: e.target.value })}
        />
        <input
          type="text"
          placeholder="From"
          value={form.location_from}
          onChange={(e) => setForm({ ...form, location_from: e.target.value })}
        />
        <input
          type="text"
          placeholder="To"
          value={form.location_to}
          onChange={(e) => setForm({ ...form, location_to: e.target.value })}
        />
        <input
          type="text"
          placeholder="Purpose"
          value={form.purpose}
          onChange={(e) => setForm({ ...form, purpose: e.target.value })}
        />
        <input
          type="text"
          placeholder="Mode of Travel"
          value={form.mode_of_travel}
          onChange={(e) =>
            setForm({ ...form, mode_of_travel: e.target.value })
          }
        />
        <input
          type="number"
          placeholder="Amount"
          value={form.amount}
          onChange={(e) => setForm({ ...form, amount: e.target.value })}
        />

        <button className="save-btn" onClick={saveTravel}>
          Save Travel Expense
        </button>
      </div>

      {/* FILTER */}
      <div className="filter-section">
        <input
          type="month"
          value={filterMonth}
          onChange={(e) => setFilterMonth(e.target.value)}
        />
      </div>

      {/* Travel Table */}
      <div className="table-card">
        <h3>Travel History</h3>

        {filteredList.length === 0 ? (
          <p>No records found</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>From → To</th>
                <th>Amount</th>
                <th>Purpose</th>
                <th>Mode</th>
                <th>Status</th>
                <th>Delete</th>
              </tr>
            </thead>
            <tbody>
              {filteredList.map((t) => (
                <tr key={t.id}>
                  <td>{t.travel_date}</td>
                  <td>
                    {t.location_from} → {t.location_to}
                  </td>
                  <td>₹{t.amount}</td>
                  <td>{t.purpose}</td>
                  <td>{t.mode_of_travel}</td>
                  <td>
                    <span
                      className={
                        t.status === "Approved" ? "status-approved" : "status-pending"
                      }
                    >
                      {t.status}
                    </span>
                  </td>
                  <td>
                    <button
                      className="delete-btn"
                      onClick={() => deleteTravel(t.id)}
                    >
                      ❌
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
